using System.Diagnostics;
using TextAnalysis;

// Build test data (~1000 words)
var words = new string[]
{
    "the", "quick", "brown", "fox", "jumps", "over", "the", "lazy", "dog",
    "benchmark", "performance", "analysis", "dotnet", "runtime", "optimization",
    "memory", "allocation", "throughput", "latency", "histogram"
};
var sb = new System.Text.StringBuilder();
for (int i = 0; i < 50; i++)
    sb.AppendJoin(' ', words).Append(' ');
var analyzer = new TextAnalyzer(sb.ToString());

Console.WriteLine($"Runtime: {System.Runtime.InteropServices.RuntimeInformation.FrameworkDescription}");
Console.WriteLine($"Words: {analyzer.WordCount}");
Console.WriteLine();

// Warmup + benchmark helper
void Bench(string name, Action action, int iterations = 500_000)
{
    // Warmup
    for (int i = 0; i < iterations / 10; i++) action();
    GC.Collect();
    GC.WaitForPendingFinalizers();
    GC.Collect();

    // Multiple rounds for stability
    var times = new double[5];
    for (int round = 0; round < 5; round++)
    {
        var sw = Stopwatch.StartNew();
        for (int i = 0; i < iterations; i++) action();
        sw.Stop();
        times[round] = sw.Elapsed.TotalMilliseconds / iterations * 1_000_000; // ns per op
    }

    Array.Sort(times);
    var median = times[2];
    var min = times[0];
    var max = times[4];
    Console.WriteLine($"{name,-25} {median,10:F1} ns/op  (min={min:F1}, max={max:F1})");
}

Bench("AverageWordLength", () => analyzer.AverageWordLength());
Bench("WordLengthHistogram", () => analyzer.WordLengthHistogram());
Bench("UniqueWordCount", () => analyzer.UniqueWordCount());

